"""HLD Key Technologies: PostgreSQL, Flink, ZooKeeper — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def postgresql_lesson() -> Lesson:
    return Lesson(id="hld-postgresql", number=122, title="PostgreSQL",
        focus=("MVCC","WAL","VACUUM","indexes","replication","partitioning","JSONB"),
        overview="PostgreSQL is the most versatile RDBMS. Know MVCC, WAL, replication, and when to use it vs alternatives.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("pg-1","What is PostgreSQL's MVCC?","hard",("postgresql",),("A replication protocol","Multi-Version Concurrency Control: each transaction sees a snapshot; readers don't block writers","A caching mechanism","An index type"),1,"MVCC: each row has xmin/xmax marking which transactions can see it. No read locks needed."),
        quiz("pg-2","What is the WAL in PostgreSQL?","hard",("postgresql",),("Write-Ahead Log: all changes recorded before applying, ensuring crash recovery and enabling replication","A caching mechanism","An index type","A query optimizer"),0,"WAL: sequential writes for durability. Streaming replication sends WAL to followers."),
        quiz("pg-3","What is VACUUM and why is it necessary?","hard",("postgresql",),("Reclaims storage from dead tuples (old row versions) left by MVCC after updates/deletes","A query optimizer","A backup tool","A replication tool"),0,"Without VACUUM, tables bloat with dead tuples. autovacuum handles this automatically in most cases."),
        quiz("pg-4","What is the difference between HOT update and regular update?","hard",("postgresql",),("Regular is in-place","HOT is slower","Heap-Only Tuple: if no indexed columns change, the new version stays on the same page — no index update needed","No difference"),2,"HOT updates avoid index maintenance, significantly improving update performance when only non-indexed columns change."),
        quiz("pg-5","What is PostgreSQL's streaming replication?","hard",("postgresql",),("Logical replication only","Manual copy","Batch replication","Continuous WAL shipping from primary to standby in real-time; standby can serve read queries"),3,"Streaming replication: sub-second lag. Synchronous mode waits for standby confirmation (slower but consistent)."),
        quiz("pg-6","What is logical replication in PostgreSQL?","hard",("postgresql",),("Physical replication","A backup feature","Same as streaming","Replicates at the logical (row/table) level instead of physical WAL; supports selective table replication"),3,"Logical replication: replicate specific tables, cross-version, or to different schemas. Uses publication/subscription."),
        quiz("pg-7","What are PostgreSQL's isolation levels?","hard",("postgresql",),("Read Committed only","Serializable only","Read Uncommitted, Read Committed (default), Repeatable Read, and Serializable","Only one level"),2,"Read Committed: sees only committed data at statement start. Serializable: full ACID, detects anomalies."),
        quiz("pg-8","What is a PostgreSQL GiST index?","hard",("postgresql",),("Generalized Search Tree: supports geometric/spatial data, full-text search, and range types","A B-tree variant","A hash index","A bitmap index"),0,"GiST: used for PostGIS geometry queries, range containment, and nearest-neighbor search."),
        quiz("pg-9","What is PostgreSQL partitioning?","medium",("postgresql",),("A backup feature","Splitting a large table into smaller physical pieces (range, list, or hash) within the same database","Replication","Sharding"),1,"Partitioning improves query performance and maintenance for large tables. Partition pruning skips irrelevant partitions."),
        quiz("pg-10","What is the JSONB type in PostgreSQL?","medium",("postgresql",),("Binary JSON with indexing support (GIN) — queryable, indexable document storage within PostgreSQL","An XML type","Same as TEXT","A string type"),0,"JSONB: store semi-structured data. Create GIN indexes for fast @>, ?, and jsonpath queries."),
        quiz("pg-11","What is connection pooling and why is it critical for PostgreSQL?","hard",("postgresql",),("PostgreSQL forks a new process per connection (~10MB each); pooling (PgBouncer) reuses connections","Not important","A replication mode","A caching feature"),0,"Without pooling, 1000 connections = 10GB RAM just for processes. PgBouncer: transaction-level pooling."),
        quiz("pg-12","What is a CTE (Common Table Expression) in PostgreSQL?","medium",("postgresql",),("A view type","A named temporary result set (WITH clause) that makes complex queries readable and can be recursive","A stored procedure","A table type"),1,"WITH RECURSIVE: powerful for tree/graph traversal (org charts, category hierarchies)."),
        quiz("pg-13","What is pg_stat_statements?","hard",("postgresql",),("An extension tracking query statistics (execution count, total time, mean time) for performance analysis","A replication monitor","A backup tool","A security tool"),0,"pg_stat_statements: find your slowest queries, most frequent queries, and optimization opportunities."),
        quiz("pg-14","What is the TOAST mechanism?","hard",("postgresql",),("A replication feature","A notification system","The Oversized-Attribute Storage Technique: automatically compresses and stores large values out-of-line","A backup system"),2,"TOAST: values >2KB are compressed and stored in a separate TOAST table. Transparent to the application."),
        quiz("pg-15","What is a tablespace in PostgreSQL?","medium",("postgresql",),("A database type","A user permission","A schema","A location on disk where database objects are stored — allows placing tables on different disks/SSDs"),3,"Put hot tables on SSD tablespace, cold data on HDD. Different performance tiers within one database."),
        quiz("pg-16","What is PostgreSQL's query planner?","hard",("postgresql",),("A SQL formatter","A replication component","The optimizer that decides how to execute a query: which indexes to use, join strategy, scan type","A cache"),2,"EXPLAIN ANALYZE: see the actual execution plan. The planner uses statistics (pg_stats) to estimate costs."),
        quiz("pg-17","What are advisory locks in PostgreSQL?","hard",("postgresql",),("A replication feature","Table locks","Row locks","Application-level cooperative locks that don't lock any actual rows — used for distributed coordination"),3,"Advisory locks: pg_advisory_lock(key). Used for job deduplication, rate limiting, and distributed locking."),
        quiz("pg-18","What is the difference between SERIAL and IDENTITY columns?","medium",("postgresql",),("SERIAL creates a sequence implicitly; IDENTITY (SQL standard) is more explicit and prevents accidental overrides","Same thing","IDENTITY is deprecated","SERIAL is newer"),0,"GENERATED ALWAYS AS IDENTITY: SQL-standard way. Prevents manual ID insertion (GENERATED BY DEFAULT allows it)."),
        quiz("pg-19","What is PostgreSQL's handling of full-text search?","hard",("postgresql",),("Not supported","Built-in tsvector/tsquery with GIN indexes — tokenization, stemming, ranking without needing Elasticsearch","Uses LIKE only","Requires Elasticsearch"),1,"pg full-text search: to_tsvector('english', text) @@ to_tsquery('search & term'). Good enough for many apps."),
        quiz("pg-20","When should you NOT use PostgreSQL?","hard",("postgresql",),("When you need massive write throughput (>100K writes/sec), horizontal scaling, or schemaless flexibility at scale","Never","When data is relational","Always use PostgreSQL"),0,"PostgreSQL scales vertically well but horizontal scaling is limited. Consider Cassandra/DynamoDB for massive writes."),
    ))

def flink_lesson() -> Lesson:
    return Lesson(id="hld-flink", number=123, title="Flink",
        focus=("stream processing","event time","watermarks","state","checkpointing","exactly-once"),
        overview="Flink is the go-to for real-time stream processing. Know event time, watermarks, and exactly-once semantics.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("flink-1","What is Apache Flink?","medium",("flink",),("A batch processor","A message queue","A database","A distributed stream processing framework with event-time semantics, stateful computation, and exactly-once guarantees"),3,"Flink processes unbounded streams in real-time. Also handles batch as a special case of streaming."),
        quiz("flink-2","What is event time vs processing time?","hard",("flink",),("Same thing","Event time is system clock","Event time: when the event actually occurred. Processing time: when the system processes it. Event time handles late arrivals","Processing time is more accurate"),2,"Event time ensures correct results even when events arrive out of order or late."),
        quiz("flink-3","What are watermarks in Flink?","hard",("flink",),("Markers declaring that no events with timestamps earlier than the watermark will arrive — triggers window computation","A checkpoint","A security feature","A timestamp"),0,"Watermarks: 'all events before time T have arrived.' Windows fire when watermark passes window end time."),
        quiz("flink-4","What is windowing in Flink?","hard",("flink",),("Grouping events into finite sets for aggregation: tumbling (fixed, non-overlapping), sliding, session, global","A caching technique","A partitioning strategy","Pagination"),0,"Tumbling: 5-min non-overlapping. Sliding: 5-min window every 1 min. Session: gap-based grouping."),
        quiz("flink-5","What is Flink's checkpointing mechanism?","hard",("flink",),("A logging feature","Periodic consistent snapshots of operator state to durable storage, enabling exactly-once recovery","A monitoring tool","Manual backup"),1,"Checkpointing: barrier flows through the graph. Each operator saves state when barrier arrives. Asynchronous."),
        quiz("flink-6","How does Flink achieve exactly-once semantics?","hard",("flink",),("Magic","At-least-once only","Checkpointing + barrier alignment + idempotent sinks or two-phase commit sinks","Impossible in practice"),2,"Exactly-once within Flink. End-to-end exactly-once requires transactional sinks (Kafka transactions, 2PC)."),
        quiz("flink-7","What is Flink's state backend?","hard",("flink",),("A database","A message queue","A configuration file","Storage for operator state: MemoryStateBackend (dev), FsStateBackend (moderate), RocksDBStateBackend (production)"),3,"RocksDB: state larger than memory, spills to disk. Incremental checkpoints for large state."),
        quiz("flink-8","What is a keyed stream in Flink?","medium",("flink",),("A filtered stream","An encrypted stream","A stream partitioned by key — all events with the same key go to the same operator instance for stateful processing","A sorted stream"),2,"keyBy(key) partitions the stream. Stateful operations (aggregations, joins) work per key."),
        quiz("flink-9","What is the difference between Flink and Spark Streaming?","hard",("flink",),("Flink: true stream processing (event-by-event). Spark: micro-batch (processes small batches). Flink has lower latency","Spark is stream processing","Flink is batch only","Same thing"),0,"Flink: millisecond latency. Spark Structured Streaming: ~100ms+ latency due to micro-batching."),
        quiz("flink-10","What is Flink's TaskManager and JobManager?","medium",("flink",),("JobManager: coordinates jobs, scheduling, checkpointing. TaskManager: executes operators, manages state","JobManager executes","TaskManager coordinates","Same thing"),0,"JobManager: brain (1 or HA pair). TaskManagers: muscle (many, run parallel tasks)."),
        quiz("flink-11","What is a Flink savepoint vs checkpoint?","hard",("flink",),("Checkpoints are manual","Savepoints are automatic","Same thing","Checkpoints are automatic and periodic; savepoints are manually triggered for upgrades, migrations, and debugging"),3,"Savepoints: portable snapshots. Use for Flink version upgrades, code changes, and cluster migrations."),
        quiz("flink-12","How does Flink handle late events?","hard",("flink",),("Allowed lateness parameter: late events within the allowed window update results; beyond that, sent to side output","Drops them","Processes them immediately","Waits forever"),0,"allowedLateness(Duration) + sideOutputLateData: handle stragglers gracefully."),
        quiz("flink-13","What is Flink's DataStream API vs Table API?","medium",("flink",),("Table API is low-level","DataStream: low-level Java/Python API for custom processing. Table API/SQL: high-level declarative queries","DataStream is SQL","Same thing"),1,"Table API: SQL-like. DataStream: full control. Both can be mixed in the same application."),
        quiz("flink-14","What is a broadcast state in Flink?","hard",("flink",),("State that is sent to all parallel instances of an operator — used for configuration updates, rule changes","A logging feature","A cache","A partition"),0,"Broadcast state: small reference data (rules, config) distributed to all operator instances."),
        quiz("flink-15","What is the operator chain optimization?","hard",("flink",),("A query optimizer","Flink chains compatible operators into a single task to avoid serialization/network overhead between them","A configuration","A deployment strategy"),1,"Chaining: map → filter → flatMap run in the same thread, avoiding serialization between each step."),
        quiz("flink-16","What is Flink CDC?","hard",("flink",),("A backup tool","A Kafka feature","A monitoring tool","Change Data Capture connectors that ingest database changes (MySQL, PostgreSQL) as a Flink stream"),3,"Flink CDC: read database binlog/WAL as a stream. Build real-time materialized views from DB changes."),
        quiz("flink-17","What is the parallelism in Flink?","medium",("flink",),("A single thread","The number of parallel instances of each operator — determines throughput and resource usage","A replication count","A configuration only"),1,"Set parallelism per operator, per job, or globally. More parallelism = more throughput but more resources."),
        quiz("flink-18","What is a process function in Flink?","hard",("flink",),("The most flexible API: access to event, state, timers, and side outputs for complex event processing","A configuration","A utility function","A monitoring callback"),0,"ProcessFunction: register timers, manage state, emit to side outputs. Full control over event processing."),
        quiz("flink-19","What is Flink's exactly-once sink with Kafka?","hard",("flink",),("At-most-once only","At-least-once only","Not possible","Two-phase commit: Flink pre-commits to Kafka during checkpoint, commits on checkpoint completion"),3,"TwoPhaseCommitSinkFunction: pre-commit on checkpoint barrier, commit on checkpoint success, abort on failure."),
        quiz("flink-20","When should you use Flink vs Kafka Streams?","hard",("flink",),("They are identical","Always Flink","Always Kafka Streams","Flink: separate cluster, complex event processing, exactly-once, large state. Kafka Streams: library, embedded in app, simpler"),3,"Kafka Streams: simple, no separate cluster, embedded. Flink: more powerful, separate cluster, advanced features."),
    ))

def zookeeper_lesson() -> Lesson:
    return Lesson(id="hld-zookeeper", number=124, title="ZooKeeper",
        focus=("znodes","watches","leader election","distributed locks","ZAB protocol","ephemeral nodes"),
        overview="ZooKeeper is the coordination service for distributed systems. Know its primitives and consensus protocol.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("zk-1","What is ZooKeeper used for?","medium",("zookeeper",),("Distributed coordination: leader election, configuration management, service discovery, distributed locking","Search indexing","Message queuing","File storage"),0,"ZooKeeper provides primitives for coordination. Used by Kafka, HBase, and Hadoop."),
        quiz("zk-2","What is a znode?","hard",("zookeeper",),("A physical server","A data node in ZooKeeper's hierarchical namespace (like a filesystem) storing up to 1MB of data","A database record","A network node"),1,"Znodes: /app/config, /app/leader. Each can hold data and have children. Like a small filesystem."),
        quiz("zk-3","What is an ephemeral znode?","hard",("zookeeper",),("A permanent node","A temporary cache","A backup node","A znode that exists only while the session that created it is alive — auto-deleted on disconnect"),3,"Ephemeral znodes: auto-cleanup when client disconnects. Foundation for leader election and service discovery."),
        quiz("zk-4","What is a sequential znode?","hard",("zookeeper",),("A sorted database","An ordered list","A znode with an auto-incrementing suffix — used for queue ordering and fair leader election","A numbered file"),2,"Create /lock/lock- with SEQUENTIAL flag → ZK appends /lock/lock-0000000001. Lowest number wins the lock."),
        quiz("zk-5","How does leader election work in ZooKeeper?","hard",("zookeeper",),("Each candidate creates an ephemeral sequential node; the node with the lowest sequence number becomes leader","Random selection","Voting protocol","Manual assignment"),0,"Leader: smallest sequence. If leader dies, ephemeral node deleted → next-smallest becomes leader."),
        quiz("zk-6","What is ZooKeeper's ZAB protocol?","hard",("zookeeper",),("A gossip protocol","A caching protocol","A load balancing algorithm","ZooKeeper Atomic Broadcast: consensus protocol ensuring all nodes agree on the order of state changes"),3,"ZAB: leader broadcasts proposals → followers acknowledge → quorum commit. Similar to Raft/Paxos."),
        quiz("zk-7","What is a watch in ZooKeeper?","hard",("zookeeper",),("A one-time notification trigger: client registers a watch on a znode and gets notified on change","A monitoring tool","A polling mechanism","A subscription"),0,"Watches are one-shot: triggered once, must re-register. Used for configuration changes, leader changes."),
        quiz("zk-8","How does distributed locking work with ZooKeeper?","hard",("zookeeper",),("File locking","Create ephemeral sequential node under /lock; lowest sequence holds the lock; watch the predecessor","A database lock","A Redis SETNX"),1,"Fair locking: each client watches only the node before it (avoids thundering herd on unlock)."),
        quiz("zk-9","What is ZooKeeper's consistency model?","hard",("zookeeper",),("No consistency","Sequential consistency with linearizable writes: writes are ordered, reads may be stale unless using sync()","Eventually consistent","Strongly consistent always"),1,"Reads can return stale data (from any server). Use sync() before read for linearizable guarantee."),
        quiz("zk-10","What is the ZooKeeper ensemble?","medium",("zookeeper",),("A group of ZK servers (typically 3 or 5) that form a quorum for fault tolerance","A single server","A client library","A monitoring tool"),0,"3 servers tolerate 1 failure. 5 servers tolerate 2. Always use odd numbers for clear majority."),
        quiz("zk-11","What is ZooKeeper's session?","hard",("zookeeper",),("An HTTP session","A database connection","A cache entry","A persistent connection between client and server with a timeout — ephemeral nodes live within a session"),3,"Session has a timeout. If client disconnects > timeout, session expires and ephemeral nodes are deleted."),
        quiz("zk-12","What is the difference between ZooKeeper and etcd?","hard",("zookeeper",),("Same thing","ZK uses Raft","etcd is Java","ZK: Java, ZAB protocol, used by Kafka/HBase. etcd: Go, Raft protocol, used by Kubernetes"),3,"etcd: simpler API (HTTP/gRPC), better for Kubernetes. ZK: more mature, used by Hadoop ecosystem."),
        quiz("zk-13","How does Kafka use ZooKeeper?","hard",("zookeeper",),("Broker registration, topic/partition metadata, controller election, and consumer group coordination (legacy)","For consumer storage","For message storage","For message routing"),0,"Kafka is moving away from ZooKeeper (KRaft mode). Previously: controller election, metadata, ACLs."),
        quiz("zk-14","What is the herd effect in ZooKeeper?","hard",("zookeeper",),("A consensus issue","A replication feature","A performance optimization","All clients watching the same node get notified simultaneously on change, causing a thundering herd"),3,"Mitigation: watch only predecessor node (distributed locking) instead of the parent node."),
        quiz("zk-15","What is ZooKeeper's data model?","medium",("zookeeper",),("Key-value store","A hierarchical tree of znodes (like a filesystem) where each node can store data and have children","A document store","A graph"),1,"Path-based: /app/config/db-host. Max 1MB per znode. Not designed for large data storage."),
        quiz("zk-16","What is a multi-operation (multi) in ZooKeeper?","hard",("zookeeper",),("Multiple connections","A replication step","A batch read","Execute multiple operations atomically: all succeed or all fail (create, set, delete in one transaction)"),3,"multi(): atomic batch operations. Create lock node + set config + delete old node atomically."),
        quiz("zk-17","What is ZooKeeper's read scalability?","hard",("zookeeper",),("No reads allowed","Only leader reads","Reads can be served by any server (not just leader) — adding more followers increases read throughput","No scalability"),2,"Reads from followers may be stale. Writes go through leader only. Read-heavy workloads scale well."),
        quiz("zk-18","What are ACLs in ZooKeeper?","medium",("zookeeper",),("A replication setting","A network feature","Access Control Lists: control which clients can read/write/create/delete znodes","A consensus feature"),2,"ACL schemes: world, auth, digest, ip. Each znode has its own ACL. Important for multi-tenant setups."),
        quiz("zk-19","What is the curator framework?","hard",("zookeeper",),("A high-level Java client library for ZooKeeper providing recipes: leader election, locks, barriers, caches","A monitoring tool","A backup framework","A UI tool"),0,"Curator simplifies ZK usage with reusable recipes. Handles connection management and retry logic."),
        quiz("zk-20","When should you NOT use ZooKeeper?","hard",("zookeeper",),("Always use ZooKeeper","When you need coordination","For storing large data (>1MB/node), high-throughput reads/writes, or as a message queue or database","Never"),2,"ZK is for small metadata and coordination. Not a general-purpose store. New projects may prefer etcd or Consul."),
    ))
